  ('aboriginal-6e11b43e-moex-00472', 'aboriginal-6e11b43e', 'aboriginal-6e11b43e-moex-110-3082b5f1', 'sub-aboriginal-6e11b43e-04', NULL, 'single_choice', '關於公務員行為構成國家賠償責任之要件，下列敘述何者錯誤？', '["須行為違法", "須侵害人民之自由或權利", "須為行使公權力或私經濟行政行為", "須於執行職務時所為"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:13+00:00", "source_pdf_sha1": "67c5b0ef133f", "answer_pdf_sha1": "92e4eae365f1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "402", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00001', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-114-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'essay', '甲公司批發銷售牛仔褲，該公司採定期盤存制。該公司於 X2 年 7 月 8
